mapper.select:
SELECT  *   /* TODO: 페이징 래퍼 - 컬럼 명시 필요 */
  FROM  (
        SELECT  ROWNUM RNUM
              , ALL_LIST.*   /* TODO: 컬럼 명시 필요 */
          FROM  (
                /* 구현 Sql */
                SELECT  CL_CODE
                      , CL_CODE_NM
                      , USE_AT
                  FROM  TB_CMMN_CL_CODE
                 WHERE  1 = 1

                   AND  CL_CODE LIKE '%' || #{searchKeyword} || '%'


                   AND  CL_CODE_NM LIKE '%' || #{searchKeyword} || '%'


                   AND  USE_AT        = 'Y'

                /* 구현 Sql */
                ) ALL_LIST
        ) Z
 WHERE  RNUM > #{firstIndex}
   AND  RNUM <= #{firstIndex} + #{recordCountPerPage}

mapper.update:
UPDATE  TB_CMMN_CL_CODE
   SET  CL_CODE_NM      = #{clCodeNm}
      , CL_CODE_DC      = #{clCodeDc}
      , USE_AT          = #{useAt}
      , LAST_UPDT_PNTTM = SYSDATETIME
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
 WHERE  CL_CODE = #{clCode}

mapper.delete:
UPDATE  TB_CMMN_CL_CODE
   SET  USE_AT = 'N'
 WHERE  CL_CODE = #{clCode}
